module RefModule(
	input [7:0] dataIn,
	output [7:0] dataOut
);reg [7:0] ctrl;
  always @ (dataIn) begin     
    case(dataIn)
      8'h1D    : ctrl = 8'd87;     
      8'h1B    : ctrl = 8'd83;
		8'h1C    : ctrl = 8'd65;
		8'h23    : ctrl = 8'd68;
      default  : ctrl = 0;     
    endcase
  end

  assign dataOut = ctrl;

endmodule
